+    #[test]
+    fn all_resource_uris_use_wa_scheme() {
+        let db = db_path();
+        let uris = [
+            WaPanesResource::new(PaneFilterConfig::default()).definition().uri,
+            WaEventsResource::new(Arc::clone(&db)).definition().uri,
